-- Session 3.2.2 fix (codex P1 on PR #38) — preserve existing contractor_profiles
-- fields on partial upsert.
--
-- upsert_contractor_profile_for_org previously cleared region, experience_years,
-- avatar_url, description, inn and specializations whenever p_profile_data omitted
-- those keys. The Визитка form omits empty optional fields and does not pre-load
-- existing values, so re-saving an existing profile silently wiped data. The
-- ON CONFLICT branch now keeps the prior column value when the corresponding key
-- is absent (jsonb_exists), while still allowing an explicit clear when the key
-- is present. create_org_with_contractor_profile (insert-only) is unaffected.

create or replace function public.upsert_contractor_profile_for_org(
  p_org_id uuid,
  p_profile_data jsonb
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_user_id uuid := auth.uid();
  v_profile_id uuid;
  v_specializations text[];
  v_requested_status text;
begin
  if v_user_id is null then
    raise exception 'Not authenticated' using errcode = '28000';
  end if;
  if not public.can_manage_org(p_org_id) then
    raise exception 'Not authorized to manage organization %', p_org_id
      using errcode = '42501';
  end if;

  v_specializations := coalesce(
    (
      select array_agg(elem)
      from jsonb_array_elements_text(
        coalesce(p_profile_data -> 'specializations', '[]'::jsonb)
      ) as elem
    ),
    '{}'::text[]
  );

  -- Clients may only request draft / pending_moderation. Publishing and
  -- archiving stay an admin-side concern; ignore anything else.
  v_requested_status := p_profile_data ->> 'status';
  if v_requested_status is null
     or v_requested_status not in ('draft', 'pending_moderation') then
    v_requested_status := null;
  end if;

  insert into public.contractor_profiles (
    org_id, display_name, contacts, region, specializations,
    experience_years, avatar_url, description, inn, status, created_by
  ) values (
    p_org_id,
    coalesce(nullif(trim(p_profile_data ->> 'display_name'), ''), 'Контакт'),
    coalesce(p_profile_data -> 'contacts', '{}'::jsonb),
    nullif(trim(p_profile_data ->> 'region'), ''),
    v_specializations,
    nullif(p_profile_data ->> 'experience_years', '')::integer,
    nullif(trim(p_profile_data ->> 'avatar_url'), ''),
    nullif(trim(p_profile_data ->> 'description'), ''),
    nullif(trim(p_profile_data ->> 'inn'), ''),
    coalesce(v_requested_status, 'draft'),
    v_user_id
  )
  on conflict (org_id) do update set
    display_name = coalesce(
      nullif(trim(p_profile_data ->> 'display_name'), ''),
      public.contractor_profiles.display_name
    ),
    contacts = case when jsonb_exists(p_profile_data, 'contacts')
      then coalesce(p_profile_data -> 'contacts', public.contractor_profiles.contacts)
      else public.contractor_profiles.contacts end,
    region = case when jsonb_exists(p_profile_data, 'region')
      then nullif(trim(p_profile_data ->> 'region'), '')
      else public.contractor_profiles.region end,
    specializations = case when jsonb_exists(p_profile_data, 'specializations')
      then v_specializations
      else public.contractor_profiles.specializations end,
    experience_years = case when jsonb_exists(p_profile_data, 'experience_years')
      then nullif(p_profile_data ->> 'experience_years', '')::integer
      else public.contractor_profiles.experience_years end,
    avatar_url = case when jsonb_exists(p_profile_data, 'avatar_url')
      then nullif(trim(p_profile_data ->> 'avatar_url'), '')
      else public.contractor_profiles.avatar_url end,
    description = case when jsonb_exists(p_profile_data, 'description')
      then nullif(trim(p_profile_data ->> 'description'), '')
      else public.contractor_profiles.description end,
    inn = case when jsonb_exists(p_profile_data, 'inn')
      then nullif(trim(p_profile_data ->> 'inn'), '')
      else public.contractor_profiles.inn end,
    status = coalesce(v_requested_status, public.contractor_profiles.status),
    updated_at = now()
  returning id into v_profile_id;

  return jsonb_build_object('org_id', p_org_id, 'profile_id', v_profile_id);
end;
$$;

revoke all on function public.upsert_contractor_profile_for_org(uuid, jsonb) from public;
grant execute on function public.upsert_contractor_profile_for_org(uuid, jsonb) to authenticated;
